// Pseudocode — implementation follows this contract exactly

function getPageSchemas(route: string): JsonLdObject[] {
  const schemas: JsonLdObject[] = []

  // Sitewide — always present
  schemas.push(buildOrganizationSchema())
  schemas.push(buildBreadcrumbSchema(route))
  schemas.push(buildWebSiteSchema()) // homepage only

  // Route-specific — per Domain 3.7.4 pull map
  if (isTourPage(route)) {
    const pkg = getPackageData(slugFromRoute(route))
    schemas.push(buildTouristTripSchema(pkg))
    const faqs = getFAQsByRoute(route)           // Domain 6.5.2
    if (faqs.length) schemas.push(buildFAQPageSchema(faqs))
  }

  if (route === '/travel-guide/ijen-health-screening') {
    schemas.push(buildMedicalWebPageSchema())
    schemas.push(buildFAQPageSchema(getFAQsByRoute(route)))
  }

  if (route === '/why-jvto/our-team') {
    schemas.push(buildCrewItemListSchema(getCrewData()))
  }

  if (route === '/verify-jvto/press-recognition') {
    schemas.push(...getPressItems().map(buildNewsArticleSchema))
  }

  if (route === '/verify-jvto/legal') {
    schemas.push(buildGovernmentPermitSchema('nib'))
    schemas.push(buildGovernmentPermitSchema('tdup'))
  }

  if (POLICY_PAGES.includes(route) || HUB_PAGES.includes(route)) {
    const faqs = getFAQsByRoute(route)
    if (faqs.length) schemas.push(buildFAQPageSchema(faqs))
  }

  return schemas
}

