// Component contract

interface JsonLdScriptProps {
  route: string
}

export function JsonLdScript({ route }: JsonLdScriptProps) {
  const schemas = getPageSchemas(route)
  return (
    <>
      {schemas.map((schema, i) => (
        <script
          key={i}
          type="application/ld+json"
          dangerouslySetInnerHTML={{ __html: JSON.stringify(schema) }}
        />
      ))}
    </>
  )
}

